it("should keep a block pattern alive where each cell has exactly 3 neighbors (survival)", () => {
  const block = [[0, 0], [1, 0], [0, 1], [1, 1]];
  const result = nextGeneration(block);
  const sort = (cells: number[][]) => [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
